namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_N = 2;
static constexpr uint32_t ALIGN_COUT = 32;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Conv2dMinAddMultiplyCustomTilingData tiling;
    // Use GetOriginShape to get the actual shape (not StorageShape)
    const auto &x_shape = context->GetInputShape(0)->GetOriginShape();
    const auto &w_shape = context->GetInputShape(1)->GetOriginShape();
    const auto &pb_shape = context->GetInputShape(3)->GetOriginShape(); // post_bias

    uint32_t n = static_cast<uint32_t>(x_shape.GetDim(0));
    uint32_t cin = static_cast<uint32_t>(x_shape.GetDim(1));
    uint32_t h_in = static_cast<uint32_t>(x_shape.GetDim(2));
    uint32_t w_in = static_cast<uint32_t>(x_shape.GetDim(3));
    uint32_t cout = static_cast<uint32_t>(w_shape.GetDim(0));
    uint32_t kernel_h = static_cast<uint32_t>(w_shape.GetDim(2));
    uint32_t kernel_w = static_cast<uint32_t>(w_shape.GetDim(3));
    uint32_t h_out = h_in - kernel_h + 1;
    uint32_t w_out = w_in - kernel_w + 1;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    // fix typo: atts -> attrs
    float constant_value = attrs->GetAttrPointer<float>(0)[0];
    float scaling_factor = attrs->GetAttrPointer<float>(1)[0];

    // Estimate UB usage per tile (simplified heuristic)
    uint32_t max_elements_ub = UB_BUDGET_BYTES / sizeof(float);
    uint32_t tile_cout = 32;
    uint32_t tile_n = 2;
    // adjust to fit UB roughly
    uint32_t input_per_tile = tile_n * tile_cout * kernel_h * kernel_w * cin;
    uint32_t weight_per_tile = tile_cout * cin * kernel_h * kernel_w;
    uint32_t output_per_tile = tile_n * tile_cout;
    uint32_t total_per_tile = input_per_tile + weight_per_tile + output_per_tile;
    if (total_per_tile > max_elements_ub) {
        if (tile_cout > 16) tile_cout = 16;
        if (tile_n > 1) tile_n = 1;
    }
    if (tile_cout > cout) tile_cout = cout;
    if (tile_n > n) tile_n = n;
    tile_cout = AlignDown(tile_cout, ALIGN_COUT);
    if (tile_cout == 0) tile_cout = ALIGN_COUT;
    tile_n = AlignDown(tile_n, ALIGN_N);
    if (tile_n == 0) tile_n = 1;

    uint32_t num_tiles_n = CeilDiv(n, tile_n);
    uint32_t num_tiles_cout = CeilDiv(cout, tile_cout);
    uint32_t total_tiles = num_tiles_n * num_tiles_cout;
    uint32_t block_dim = total_tiles;
    if (block_dim < 8) block_dim = 8;
    if (block_dim > 24) block_dim = 24;

    context->SetBlockDim(block_dim);

    tiling.set_n(n);
    tiling.set_cin(cin);
    tiling.set_h_in(h_in);
    tiling.set_w_in(w_in);
    tiling.set_cout(cout);
    tiling.set_kernel_h(kernel_h);
    tiling.set_kernel_w(kernel_w);
    tiling.set_h_out(h_out);
    tiling.set_w_out(w_out);
    tiling.set_tile_n(tile_n);
    tiling.set_tile_cout(tile_cout);
    tiling.set_block_dim(block_dim);
    tiling.set_constant_value(constant_value);
    tiling.set_scaling_factor(scaling_factor);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

